import{_ as t}from"./chunks/微笑狼的公开仓库.gGdYP2E_.js";import{_ as e,o as s,c as i,a2 as d}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Auto Tagging","description":"","frontmatter":{},"headers":[],"relativePath":"ps/Other/auto-tagging.md","filePath":"ps/Other/auto-tagging.md","lastUpdated":1781962217000}'),o={name:"ps/Other/auto-tagging.md"};function l(n,a,g,p,c,r){return s(),i("div",null,[...a[0]||(a[0]=[d('<h1 id="auto-tagging" tabindex="-1">Auto Tagging <a class="header-anchor" href="#auto-tagging" aria-label="Permalink to &quot;Auto Tagging&quot;">​</a></h1><p>Auto tagging دلته تنظیمېږي:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Auto Tagging</span></span></code></pre></div><p>دا په اتومات ډول image tags جوړوي، چې د search، random image filtering، public gallery filtering او age-rating access control لپاره ګټور دي.</p><h2 id="auto-tagging-څه-کولای-شي" tabindex="-1">Auto Tagging څه کولای شي <a class="header-anchor" href="#auto-tagging-څه-کولای-شي" aria-label="Permalink to &quot;Auto Tagging څه کولای شي&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>تشریح</th></tr></thead><tbody><tr><td>Generate content tags</td><td>د people، scenes، objects، art style او ورته visual content لپاره tags اضافه کوي.</td></tr><tr><td>Generate character tags</td><td>د anime images او illustrations لپاره ګټور دی.</td></tr><tr><td>Add orientation tags</td><td><code>landscape</code>، <code>portrait</code> یا <code>square</code> اضافه کوي.</td></tr><tr><td>Add image rating</td><td>د general، sensitive، questionable یا explicit content لپاره <code>G/S/Q/E</code> rating results خوندي کوي.</td></tr><tr><td>Auto-tag on upload</td><td>نوي uploaded images په اتومات ډول tagging flow ته داخلېږي.</td></tr><tr><td>Batch tagging</td><td>زړو images ته په ټولو folders یا ټاکلو folders کې tags اضافه کوي.</td></tr></tbody></table><h2 id="مخکې-څه-ته-اړتیا-لرئ" tabindex="-1">مخکې څه ته اړتیا لرئ <a class="header-anchor" href="#مخکې-څه-ته-اړتیا-لرئ" aria-label="Permalink to &quot;مخکې څه ته اړتیا لرئ&quot;">​</a></h2><p>لږ تر لږه یو accessible Hugging Face Space URL برابر کړئ.</p><p>سپارښتنه دا ده چې د SmilingWolf <code>wd-tagger</code> Space خپل Hugging Face account ته duplicate کړئ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><p>د لنډې ازموینې لپاره public Space کارولای شئ، خو public Spaces ډېر users شریکوي او ممکن queue، slow down یا unavailable شي. ستاسو په خپل account کې duplicated Space د اوږدمهاله auto tagging لپاره عموما ثابت وي.</p><h2 id="د-smilingwolf-space-duplicate-کول" tabindex="-1">د SmilingWolf Space Duplicate کول <a class="header-anchor" href="#د-smilingwolf-space-duplicate-کول" aria-label="Permalink to &quot;د SmilingWolf Space Duplicate کول&quot;">​</a></h2><ol><li>Hugging Face ته sign in وکړئ.</li><li><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code> پرانیزئ.</li></ol><p><img src="'+t+`" alt="SmilingWolf public Space" loading="lazy"></p><ol start="3"><li>په ښي پورتني کونج کې three-dot menu کلیک کړئ.</li><li><code>Duplicate this Space</code> وټاکئ.</li><li>default Space name وساتئ یا خپل نوم ورکړئ، لکه <code>wd-tagger</code>.</li><li>visibility پر <code>Public</code> وټاکئ. Public Spaces د ImgBed لپاره call کول اسانه وي.</li><li>په پیل کې default free hardware وساتئ. یوازې هغه وخت upgrade وکړئ چې queueing څرګند شي.</li><li>Space جوړ کړئ او د build تر بشپړېدو انتظار وکړئ.</li></ol><p>کله چې build بشپړ شو، خپل Space page پرانیزئ. URL عموما داسې ښکاري:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/your-name/wd-tagger</span></span></code></pre></div><p>browser URL copy کړئ او د ImgBed په <code>Space URLs</code> کې یې paste کړئ.</p><h2 id="څو-space-urls-ډکول" tabindex="-1">څو Space URLs ډکول <a class="header-anchor" href="#څو-space-urls-ډکول" aria-label="Permalink to &quot;څو Space URLs ډکول&quot;">​</a></h2><p>په هر line کې یو Space URL ولیکئ.</p><p>بېلګې:</p><table tabindex="0"><thead><tr><th>Value</th><th>تشریح</th></tr></thead><tbody><tr><td><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code></td><td>SmilingWolf public Space. د لنډې ازموینې لپاره ښه دی.</td></tr><tr><td><code>https://huggingface.co/spaces/lintonxue00/wd-tagger</code></td><td>د copied Space page URL.</td></tr><tr><td><code>https://huggingface.co/spaces/your-name/wd-tagger</code></td><td>ستاسو خپل duplicated Space page URL.</td></tr></tbody></table><p>څو URLs داخلولای شئ. ImgBed څو Spaces یو ځای کاروي، چې speed ښه کولای شي.</p><p>که یو Space موقتا unavailable شي، نور Spaces processing ته دوام ورکولای شي.</p><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>سپارښتنه</th></tr></thead><tbody><tr><td><code>Space URLs</code></td><td>هغه Space URLs ولیکئ چې برابر کړي مو دي. لږ تر لږه یو وکاروئ.</td></tr><tr><td>Target folder</td><td>د ټولو folders لپاره تش پرېږدئ. یوازې هغه وخت folder وټاکئ چې ځانګړی directory process کوئ.</td></tr><tr><td>Recognition model</td><td>default <code>wd-swinv2-tagger-v3</code> وساتئ.</td></tr><tr><td>General tag threshold</td><td>default د ډېرو images لپاره ښه کار کوي. ټیټ values ډېر tags جوړوي؛ لوړ values لږ tags جوړوي.</td></tr><tr><td>Character tag threshold</td><td>default محافظه کار دی او د غلط character tags کمولو کې مرسته کوي.</td></tr><tr><td><code>MCut</code> automatic threshold</td><td>په پیل کې off پرېږدئ. هغه وخت یې on کړئ چې غواړئ model په اتومات ډول tag count وټاکي.</td></tr><tr><td>Auto-tag on upload</td><td>که نوي uploaded images باید په اتومات ډول tags واخلي، on یې کړئ.</td></tr><tr><td>Start tagging</td><td>زاړه images manually batch-tag کوي.</td></tr></tbody></table><h2 id="سپارښتل-شوي-پیل-values" tabindex="-1">سپارښتل شوي پیل values <a class="header-anchor" href="#سپارښتل-شوي-پیل-values" aria-label="Permalink to &quot;سپارښتل شوي پیل values&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Recommended Value</th></tr></thead><tbody><tr><td>Recognition model</td><td><code>wd-swinv2-tagger-v3</code></td></tr><tr><td>General tag threshold</td><td><code>0.35</code></td></tr><tr><td>Character tag threshold</td><td><code>0.85</code></td></tr><tr><td><code>MCut</code></td><td>په پیل کې Off</td></tr><tr><td>Auto-tag on upload</td><td>د اړتیا پر وخت Enable</td></tr></tbody></table><p>که tags ډېر وي، general threshold لږ لوړ کړئ.</p><p>که tags کم وي، general threshold لږ ټیټ کړئ.</p><h2 id="batch-tagging" tabindex="-1">Batch Tagging <a class="header-anchor" href="#batch-tagging" aria-label="Permalink to &quot;Batch Tagging&quot;">​</a></h2><ol><li><code>Space URLs</code> ډک کړئ.</li><li>target folder وټاکئ.</li><li>start tagging کلیک کړئ.</li><li>د progress تر بشپړېدو انتظار وکړئ.</li></ol><p>که target folder تش وي، ImgBed ټول folders process کوي.</p><p>Batch tagging د زړو images لپاره ښه دی. د نویو images لپاره auto-tag on upload فعال کړئ، څو هر ځل یې manually ونه چلوئ.</p><h2 id="auto-tag-on-upload" tabindex="-1">Auto-Tag on Upload <a class="header-anchor" href="#auto-tag-on-upload" aria-label="Permalink to &quot;Auto-Tag on Upload&quot;">​</a></h2><p>کله چې auto-tag on upload فعال شي، نوي uploaded images په اتومات ډول configured <code>Space URLs</code> call کوي.</p><p>دا د اوږدمهاله کارونې لپاره مناسب دی.</p><p>که ستاسو Space queue ولري، upload پخپله مخکې بشپړېدای شي او tagging وروسته دوام کوي.</p><h2 id="کوم-images-process-کېږي" tabindex="-1">کوم Images Process کېږي <a class="header-anchor" href="#کوم-images-process-کېږي" aria-label="Permalink to &quot;کوم Images Process کېږي&quot;">​</a></h2><p>Auto tagging عموما image files process کوي.</p><p>هغه images چې complete tags، orientation، rating، width او height لا لري، skipped کېږي څو unnecessary Space calls ونه شي.</p><p>ImgBed د امکان تر حده یوازې missing information ډکوي. د بېلګې په توګه، که یوازې orientation missing وي، هڅه کوي orientation اضافه کړي، پرته له دې چې full content tag flow call کړي.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="ولې-خپل-space-duplicate-کړم؟" tabindex="-1">ولې خپل Space Duplicate کړم؟ <a class="header-anchor" href="#ولې-خپل-space-duplicate-کړم؟" aria-label="Permalink to &quot;ولې خپل Space Duplicate کړم؟&quot;">​</a></h3><p>Public Spaces ډېر users شریکوي. ستاسو خپل duplicated Space عموما یوازې ستاسو ImgBed site کاروي، نو معمولا چټک او reliable وي.</p><h3 id="space-تل-starting-up-ښيي" tabindex="-1">Space تل Starting Up ښيي <a class="header-anchor" href="#space-تل-starting-up-ښيي" aria-label="Permalink to &quot;Space تل Starting Up ښيي&quot;">​</a></h3><p>له لومړي جوړېدو وروسته، یا له اوږده idle وخت وروسته، Space ښايي د start لپاره وخت وغواړي.</p><p>لومړی خپل Space page پرانیزئ. کله چې image عادي recognize کړي، بېرته ImgBed ته راشئ او tagging پیل کړئ.</p><h3 id="space-url-څنګه-copy-کړم؟" tabindex="-1">Space URL څنګه Copy کړم؟ <a class="header-anchor" href="#space-url-څنګه-copy-کړم؟" aria-label="Permalink to &quot;Space URL څنګه Copy کړم؟&quot;">​</a></h3><p>خپل Hugging Face Space page پرانیزئ او browser address copy کړئ.</p><p>بېلګې:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/lintonxue00/wd-tagger</span></span>
<span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><h3 id="څو-spaces-اضافه-کولای-شم؟" tabindex="-1">څو Spaces اضافه کولای شم؟ <a class="header-anchor" href="#څو-spaces-اضافه-کولای-شم؟" aria-label="Permalink to &quot;څو Spaces اضافه کولای شم؟&quot;">​</a></h3><p>هو. په هر line کې یو Space URL ولیکئ.</p><p>څو Spaces images یو ځای process کوي او هغه وخت ګټور دي چې ډېر images لرئ.</p><h3 id="ولې-tags-په-english-دي؟" tabindex="-1">ولې Tags په English دي؟ <a class="header-anchor" href="#ولې-tags-په-english-دي؟" aria-label="Permalink to &quot;ولې Tags په English دي؟&quot;">​</a></h3><p>SmilingWolf models English tags output کوي. دا عادي خبره ده.</p><p>tags عموما د search، filtering، random image API او public gallery filters لپاره کارېږي.</p><h3 id="rating-tags-د-څه-لپاره-کارېږي؟" tabindex="-1">Rating Tags د څه لپاره کارېږي؟ <a class="header-anchor" href="#rating-tags-د-څه-لپاره-کارېږي؟" aria-label="Permalink to &quot;Rating Tags د څه لپاره کارېږي؟&quot;">​</a></h3><p>rating results د Security Settings له access mode سره کار کوي.</p><p>د بېلګې په توګه، که visitor access د age rating له مخې محدود وي، public browsing او random image features د هماغو rules له مخې images filter کوي.</p><h2 id="چټک-بهیر" tabindex="-1">چټک بهیر <a class="header-anchor" href="#چټک-بهیر" aria-label="Permalink to &quot;چټک بهیر&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Sign in to Hugging Face</span></span>
<span class="line"><span>-&gt; Open SmilingWolf/wd-tagger</span></span>
<span class="line"><span>-&gt; Duplicate this Space</span></span>
<span class="line"><span>-&gt; Wait for the Space to build</span></span>
<span class="line"><span>-&gt; Copy your Space URL</span></span>
<span class="line"><span>-&gt; Fill Space URLs in ImgBed</span></span>
<span class="line"><span>-&gt; Choose model and thresholds</span></span>
<span class="line"><span>-&gt; Start tagging or enable auto-tag on upload</span></span></code></pre></div>`,63)])])}const b=e(o,[["render",l]]);export{m as __pageData,b as default};
